import { LRUCache } from "lru-cache";
const newLru = () => new LRUCache({ max: 1000 });
export class Cache {
    constructor() {
        this.slashDate = newLru();
        this.roundDateUp = newLru();
        this.ranges = newLru();
    }
}
export class Caches {
    constructor() {
        this.zones = newLru();
        this.yaml = newLru();
        this.caches = [];
    }
    zone(timezone) {
        for (let i = 0; i < this.caches.length; i++) {
            if (this.caches[i][0].equals(timezone)) {
                return this.caches[i][1];
            }
        }
        const cache = new Cache();
        this.caches.push([timezone, cache]);
        return cache;
    }
}
